#[no_mangle]
pub extern "C" fn gf4_extract_sign(value: u8) -> i8 {
    // Extract sign bit from GF4
    ((value >> 3) & 1) as i8
}

#[no_mangle]
pub extern "C" fn gf4_extract_exponent(value: u8) -> i8 {
    // Extract exponent from GF4
    ((value >> 2) & 1) as i8
}

#[no_mangle]
pub extern "C" fn gf4_extract_mantissa(value: u8) -> i16 {
    // Extract mantissa from GF4
    (value & 3) as i16
}

#[no_mangle]
pub extern "C" fn gf8_extract_sign(value: u8) -> i8 {
    // Extract sign bit from GF8
    ((value >> 7) & 1) as i8
}

#[no_mangle]
pub extern "C" fn gf8_extract_exponent(value: u8) -> i8 {
    // Extract exponent from GF8 (bits 6:4)
    ((value >> 4) & 7) as i8
}

#[no_mangle]
pub extern "C" fn gf8_extract_mantissa(value: u8) -> i16 {
    // Extract mantissa from GF8 (bits 3:0)
    (value & 15) as i16
}

